INSERT INTO products ("id", "company_id", "category_id", "name", "sku", "barcode", "description", "price", "cost_price", "compare_at_price", "min_stock", "stock", "unit", "has_variants", "image_url", "images", "is_active", "is_featured", "seo_title", "seo_description", "slug", "tags", "attributes", "metadata", "created_at", "updated_at", "deleted_at") VALUES
('8be1f2bb-b9e6-4c7c-ac1d-cd19e4033075', '65ba11df-da2e-4e8a-adca-7ad4401bb6ea', '968fc2c4-106a-44e7-be80-630d4a33245b', 'Парапетный котел КСГЗ - 7 Е "Очаг" Compact', '0053', '', 'Полная независимость от внешних источников электроэнергии. Благодаря закрытой камере сгорания не сжигается воздух из отапливаемого помещения. Патрубки - Ду 50 мм обеспечивают работу котла без циркуляционного насоса. Предусмотрена защита дымохода от задувания. Дымоход входит в комплект поставки. Не требуется дорогостоящая конструкция дымоходной трубы. Удобство монтажа обеспечивает универсальный подвод газа и теплоносителя с двух сторон. В обслуживании удобен благодаря съёмным турбулизаторам и съёмным элементам облицовки. Высококачественная фольгированная теплоизоляция обеспечивает высокий КПД. Габариты котла позволяют легко и удобно разместить его в интерьере помещения. Комплектация газовыми блоками EUROSIT гарантирует оптимальную теплоотдачу котла.
